import { useState, useEffect } from 'react';

function UserProfile({ userId }: { userId: number }) {
  const [user, setUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);

  // Fetch data when userId changes
  useEffect(() => {
    let cancelled = false; // Prevent state updates on unmounted component

    async function loadUser() {
      setLoading(true);
      try {
        const res = await fetch(`/api/users/${userId}`);
        const data = await res.json();
        if (!cancelled) {
          setUser(data);
        }
      } finally {
        if (!cancelled) {
          setLoading(false);
        }
      }
    }

    loadUser();

    // Cleanup: runs when userId changes or component unmounts
    return () => {
      cancelled = true;
    };
  }, [userId]); // Re-run when userId changes

  if (loading) return <p>Loading...</p>;
  if (!user) return <p>User not found.</p>;
  return <h1>{user.name}</h1>;
}

import { useRef, useEffect } from 'react';

function TextInput() {
  // useRef: access DOM elements directly
  const inputRef = useRef<HTMLInputElement>(null);

  // Focus the input on mount
  useEffect(() => {
    inputRef.current?.focus();
  }, []);

  return <input ref={inputRef} placeholder="Auto-focused!" />;
}

function StopWatch() {
  // useRef: store mutable values that do NOT trigger re-renders
  const intervalRef = useRef<NodeJS.Timeout | null>(null);
  const [seconds, setSeconds] = useState(0);

  function start() {
    if (intervalRef.current) return; // Already running
    intervalRef.current = setInterval(() => {
      setSeconds((prev) => prev + 1);
    }, 1000);
  }

  function stop() {
    if (intervalRef.current) {
      clearInterval(intervalRef.current);
      intervalRef.current = null;
    }
  }

  return (
    <div>
      <p>{seconds}s</p>
      <button onClick={start}>Start</button>
      <button onClick={stop}>Stop</button>
    </div>
  );
}

import { useState, useMemo, useCallback } from 'react';

interface Product {
  id: number;
  name: string;
  price: number;
  category: string;
}

function ProductList({ products }: { products: Product[] }) {
  const [search, setSearch] = useState('');
  const [sortBy, setSortBy] = useState<'name' | 'price'>('name');

  // useMemo: cache expensive computations
  // Only recalculates when products, search, or sortBy changes
  const filteredProducts = useMemo(() => {
    return products
      .filter((p) => p.name.toLowerCase().includes(search.toLowerCase()))
      .sort((a, b) => {
        if (sortBy === 'price') return a.price - b.price;
        return a.name.localeCompare(b.name);
      });
  }, [products, search, sortBy]);

  // useCallback: cache a function reference
  // Useful when passing callbacks to memoized child components
  const handleProductClick = useCallback((productId: number) => {
    console.log('Clicked product:', productId);
  }, []); // No dependencies = same function reference every render

  return (
    <div>
      <input value={search} onChange={(e) => setSearch(e.target.value)} />
      <p>Showing {filteredProducts.length} of {products.length} products</p>
      {filteredProducts.map((p) => (
        <div key={p.id} onClick={() => handleProductClick(p.id)}>
          {p.name} - ${p.price}
        </div>
      ))}
    </div>
  );
}
